<?php
$inversion=0;$valorVenta=0;foreach($productos as $p){$inversion+=(float)($p['precio_costo']??0);$valorVenta+=(float)($p['precio_final']??$p['precio_venta']??$p['precio']??0);} $ingresos=0;$ventasCount=0;$porMes=[];foreach($ventas as $v){$total=(float)($v['total']??0);$ingresos+=$total;$ventasCount++;$mes=substr((string)($v['fecha']??$v['created_at']??date('Y-m')),0,7);$porMes[$mes]=($porMes[$mes]??0)+$total;}foreach($manuales as $m){$total=(float)($m['total']??0);$ingresos+=$total;$ventasCount++;$mes=substr((string)($m['fecha']??$m['created_at']??date('Y-m')),0,7);$porMes[$mes]=($porMes[$mes]??0)+$total;}foreach(($pedidos??[]) as $p){if(($p['estado']??'')==='vendido'){$total=(float)($p['vendido_total']??$p['vendido_precio_final']??$p['producto_precio']??0);$ingresos+=$total;$ventasCount++;$mes=substr((string)($p['vendido_at']??$p['created_at']??date('Y-m')),0,7);$porMes[$mes]=($porMes[$mes]??0)+$total;}}ksort($porMes);$recuperado=min($ingresos,$inversion);$faltante=max(0,$inversion-$ingresos);$ganancia=$ingresos-$inversion;$ticket=$ventasCount?($ingresos/$ventasCount):0;$maxMes=max($porMes?:[1]);?>
<section class="page-head"><h1>Contabilidad</h1><p>Inversión, recuperación, ingresos y ganancia real.</p></section><div class="kpi-grid"><div class="kpi"><span>Inversión total</span><strong><?= money_ar($inversion) ?></strong></div><div class="kpi"><span>Recuperado</span><strong><?= money_ar($recuperado) ?></strong></div><div class="kpi"><span>Falta recuperar</span><strong><?= money_ar($faltante) ?></strong></div><div class="kpi"><span>Ganancia real</span><strong><?= money_ar($ganancia) ?></strong></div></div>
<div class="chart-panel"><div class="panel"><h2>Resumen de caja</h2><div class="money-chart pro-chart"><div><span>Inversión</span><i style="height:<?= min(260,max(25,$inversion/900)) ?>px"></i><strong><?= money_ar($inversion) ?></strong></div><div><span>Ingresos</span><i class="green" style="height:<?= min(260,max(25,$ingresos/900)) ?>px"></i><strong><?= money_ar($ingresos) ?></strong></div><div><span>Faltante</span><i class="red" style="height:<?= min(260,max(25,$faltante/900)) ?>px"></i><strong><?= money_ar($faltante) ?></strong></div></div></div><div class="panel"><h2>Indicadores</h2><div class="stat-list"><div class="stat-line"><span>Ventas registradas</span><strong><?= $ventasCount ?></strong></div><div class="stat-line"><span>Ticket promedio</span><strong><?= money_ar($ticket) ?></strong></div><div class="stat-line"><span>Valor de venta cargado</span><strong><?= money_ar($valorVenta) ?></strong></div></div></div></div>
<div class="panel"><h2>Ingresos por mes</h2><?php if(!$porMes): ?><p class="muted">Todavía no hay ventas registradas.</p><?php endif; ?><?php foreach($porMes as $mes=>$total): ?><div class="bar-row"><span><?= e($mes) ?></span><div><i style="width:<?= max(5,($total/$maxMes)*100) ?>%"></i></div><strong><?= money_ar($total) ?></strong></div><?php endforeach; ?></div>
